const items = [];
const cutoff = Date.now() - 2 * 60 * 60 * 1000; // Letzte 2 Stunden

for (const item of $input.all()) {
  const article = item.json;
  const pubDate = article.pubDate || article.isoDate;
  if (!pubDate) continue;

  const pubMs = new Date(pubDate).getTime();
  if (pubMs < cutoff) continue; // Zu alt

  const url = article.link || article.guid || '';
  const title = article.title || '(kein Titel)';
  const source = article.feed?.title || 'Nachrichten';

  items.push({
    json: {
      source: 'news',
      source_id: url || `news-${pubMs}`,
      summary: `${source}: ${title}`,
      priority: 'low',
      customer_id: $env.CUSTOMER_ID || null,
      buddy_id: $env.BUDDY_ID || null,
      timestamp: pubDate,
      details: {
        headline: title,
        url: url,
        source_name: source,
        published_at: pubDate,
        categories: article.categories || []
      }
    }
  });
}

// Max 5 Artikel pro Durchlauf
return items.slice(0, 5);
